// Program.cs — JobSimulator using System; using System.Threading; using System.Threading.Tasks; Console.WriteLine("=== Job Simulator v1.0 ==="); await Task.WhenAll( RunCalculator(), RunLogger() ); static async Task RunCalculator() { Console.WriteLine("[Calc] Iniciando..."); for (int i = 1; i <= 5; i++) { // BUG proposital: divisão por zero quando i == 3 int divisor = (i == 3) ? 0 : i; double result = 100.0 / divisor; Console.WriteLine($"[Calc] 100 / {i} = {result:F2}"); await Task.Delay(500); } Console.WriteLine("[Calc] Concluído."); } static async Task RunLogger() { Console.WriteLine("[Log] Iniciando..."); for (int i = 1; i <= 5; i++) { Console.WriteLine($"[Log] Entrada #{i} registrada em {DateTime.Now:HH:mm:ss}"); await Task.Delay(800); } Console.WriteLine("[Log] Concluído."); }
